{
  "name": "Kingspan Roof Calculator Pro",
  "description": "A high-performance technical calculator for single-slope roof projects, featuring material estimation, technical analysis, and AI-powered expert advice for construction optimization."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface RoofInputs {
  ancho: number;
  proyeccion: number;
  pendiente: number;
  separacion: number;
}

export interface CalculationResult {
  label: string;
  value: string;
  numericValue: number;
  unit: string;
  color: string;
  description: string;
}

export interface AdvisorResponse {
  advice: string;
  recommendations: string[];
  safetyTips: string[];
}

import { RoofInputs, CalculationResult } from '../types';

export const calculateRoofData = (inputs: RoofInputs): CalculationResult[] => {
  const { ancho, proyeccion, pendiente, separacion } = inputs;

  const ratio = pendiente / 100;
  const longitudReal = proyeccion * Math.sqrt(1 + Math.pow(ratio, 2));
  const traslapos = Math.floor(longitudReal / 11.8);
  const areaFaldon = ancho * longitudReal;

  // Real panel area considering technical overlap of 20cm if applicable
  const areaReal = (longitudReal + (traslapos * 0.20)) * Math.ceil(ancho);

  // Accessories
  const numCorreas = Math.ceil((longitudReal + 0.6) / separacion);
  const remateNivel = Math.ceil((longitudReal * 2 + ancho) / 2.9) * 3;
  const remateFrontal = Math.ceil(ancho / 2.9) * 3;

  // Fasteners (Optimized formula)
  const tornillos = (Math.ceil(ancho) * 2 + 1) * (numCorreas - traslapos) + (Math.ceil(ancho) * 4 + 1) * traslapos;

  return [
    { 
      label: 'Longitud de Vertiente', 
      value: `${longitudReal.toFixed(2)} m`, 
      numericValue: longitudReal,
      unit: 'm',
      color: 'blue',
      description: 'Longitud real medida sobre la pendiente de la cubierta.'
    },
    { 
      label: 'Traslapos Necesarios', 
      value: `${traslapos} und`, 
      numericValue: traslapos,
      unit: 'und',
      color: 'amber',
      description: 'Cantidad de traslapos longitudinales por línea de panel.'
    },
    { 
      label: 'Área Neta Cubierta', 
      value: `${areaFaldon.toFixed(2)} m²`, 
      numericValue: areaFaldon,
      unit: 'm²',
      color: 'emerald',
      description: 'Superficie geométrica exacta de la cubierta.'
    },
    { 
      label: 'Área Real Panel (Compra)', 
      value: `${areaReal.toFixed(1)} m²`, 
      numericValue: areaReal,
      unit: 'm²',
      color: 'indigo',
      description: 'Área total de material incluyendo desperdicio técnico y traslapos.'
    },
    { 
      label: 'Remate Nivel/Muro', 
      value: `${remateNivel} m`, 
      numericValue: remateNivel,
      unit: 'm',
      color: 'slate',
      description: 'Longitud total de accesorios de remate lateral y superior.'
    },
    { 
      label: 'Remate Frontal', 
      value: `${remateFrontal} m`, 
      numericValue: remateFrontal,
      unit: 'm',
      color: 'slate',
      description: 'Accesorios necesarios para el cierre frontal de la vertiente.'
    },
    { 
      label: 'Kits de Anclaje (Tornillos)', 
      value: `${Math.round(tornillos)} und`, 
      numericValue: Math.round(tornillos),
      unit: 'und',
      color: 'red',
      description: 'Tornillería técnica recomendada para fijación a estructura.'
    }
  ];
};

import React from 'react';
import { CalculationResult } from '../types';

interface ResultCardProps {
  result: CalculationResult;
}

const ResultCard: React.FC<ResultCardProps> = ({ result }) => {
  const colorMap: Record<string, string> = {
    blue: 'border-blue-500 bg-blue-50/50',
    amber: 'border-amber-500 bg-amber-50/50',
    emerald: 'border-emerald-500 bg-emerald-50/50',
    indigo: 'border-indigo-500 bg-indigo-50/50',
    slate: 'border-slate-500 bg-slate-50/50',
    red: 'border-red-500 bg-red-50/50',
  };

  const textColorMap: Record<string, string> = {
    blue: 'text-blue-700',
    amber: 'text-amber-700',
    emerald: 'text-emerald-700',
    indigo: 'text-indigo-700',
    slate: 'text-slate-700',
    red: 'text-red-700',
  };

  return (
    <div className={`group relative overflow-hidden rounded-xl border-l-4 p-4 shadow-sm transition-all duration-300 hover:-translate-y-1 hover:shadow-md ${colorMap[result.color] || 'border-gray-500 bg-gray-50'}`}>
      <div className="flex justify-between items-start">
        <div className="space-y-1">
          <p className="text-xs font-semibold uppercase tracking-wider text-slate-500">{result.label}</p>
          <p className={`text-xl font-bold ${textColorMap[result.color] || 'text-slate-800'}`}>{result.value}</p>
        </div>
      </div>
      <p className="mt-2 text-[10px] text-slate-400 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
        {result.description}
      </p>
    </div>
  );
};

export default ResultCard;

import React, { useState } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { CalculationResult, RoofInputs, AdvisorResponse } from '../types';

interface GeminiExpertProps {
  inputs: RoofInputs;
  results: CalculationResult[];
}

const GeminiExpert: React.FC<GeminiExpertProps> = ({ inputs, results }) => {
  const [loading, setLoading] = useState(false);
  const [advisorData, setAdvisorData] = useState<AdvisorResponse | null>(null);
  const [error, setError] = useState<string | null>(null);

  const askExpert = async () => {
    setLoading(true);
    setError(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Act as a senior Kingspan structural engineer. Analyze these roof calculation results for a single-slope project:
      Inputs: Width ${inputs.ancho}m, Projection ${inputs.proyeccion}m, Slope ${inputs.pendiente}%, Purlin Spacing ${inputs.separacion}m.
      Calculated: Slope Length ${results[0].value}, Overlaps ${results[1].value}, Net Area ${results[2].value}, Real Material Area ${results[3].value}, Screws ${results[6].value}.

      Provide a professional technical assessment in Spanish focusing on:
      1. Structural feasibility based on the slope.
      2. Material optimization advice.
      3. Specific safety or installation tips for these dimensions.`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              advice: { type: Type.STRING, description: "General professional assessment" },
              recommendations: { 
                type: Type.ARRAY, 
                items: { type: Type.STRING },
                description: "List of material or structural recommendations"
              },
              safetyTips: { 
                type: Type.ARRAY, 
                items: { type: Type.STRING },
                description: "Safety considerations for installation"
              }
            },
            required: ["advice", "recommendations", "safetyTips"]
          }
        }
      });

      const data = JSON.parse(response.text || '{}');
      setAdvisorData(data);
    } catch (err) {
      console.error(err);
      setError("No se pudo conectar con el Asesor Experto. Por favor intente más tarde.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="mt-8 bg-white rounded-2xl border border-blue-100 shadow-xl overflow-hidden transition-all duration-500">
      <div className="bg-gradient-to-r from-blue-700 to-blue-900 p-6 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <div className="bg-blue-400/20 p-2 rounded-lg">
            <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
            </svg>
          </div>
          <h3 className="text-xl font-bold text-white">Asesor Experto AI</h3>
        </div>
        {!advisorData && (
          <button 
            onClick={askExpert}
            disabled={loading}
            className="px-4 py-2 bg-white text-blue-900 font-bold rounded-lg hover:bg-blue-50 transition-colors disabled:opacity-50"
          >
            {loading ? 'Analizando...' : 'Analizar Proyecto'}
          </button>
        )}
      </div>

      {loading && (
        <div className="p-12 flex flex-col items-center justify-center space-y-4">
          <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-500 font-medium animate-pulse">Generando reporte técnico detallado...</p>
        </div>
      )}

      {error && (
        <div className="p-6 bg-red-50 text-red-600 text-center font-medium">
          {error}
        </div>
      )}

      {advisorData && !loading && (
        <div className="p-6 space-y-6 animate-fade-in">
          <div className="bg-blue-50/50 p-4 rounded-xl border border-blue-100">
            <h4 className="text-sm font-bold text-blue-900 uppercase tracking-widest mb-2">Evaluación Profesional</h4>
            <p className="text-slate-700 leading-relaxed text-sm italic">"{advisorData.advice}"</p>
          </div>

          <div className="grid md:grid-cols-2 gap-6">
            <div>
              <h4 className="text-sm font-bold text-emerald-700 uppercase mb-3 flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full"></span> Recomendaciones
              </h4>
              <ul className="space-y-2">
                {advisorData.recommendations.map((item, idx) => (
                  <li key={idx} className="text-sm text-slate-600 flex gap-2">
                    <span className="text-emerald-500 font-bold">•</span> {item}
                  </li>
                ))}
              </ul>
            </div>
            <div>
              <h4 className="text-sm font-bold text-amber-700 uppercase mb-3 flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-amber-500 rounded-full"></span> Seguridad y Obra
              </h4>
              <ul className="space-y-2">
                {advisorData.safetyTips.map((item, idx) => (
                  <li key={idx} className="text-sm text-slate-600 flex gap-2">
                    <span className="text-amber-500 font-bold">•</span> {item}
                  </li>
                ))}
              </ul>
            </div>
          </div>

          <div className="flex justify-end pt-4 border-t border-slate-100">
            <button 
              onClick={() => setAdvisorData(null)}
              className="text-xs text-slate-400 hover:text-blue-600 transition-colors"
            >
              Nuevo análisis
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default GeminiExpert;

import React, { useState, useEffect, useCallback } from 'react';
import { RoofInputs, CalculationResult } from './types';
import { calculateRoofData } from './utils/calculations';
import ResultCard from './components/ResultCard';
import GeminiExpert from './components/GeminiExpert';

const App: React.FC = () => {
  const [inputs, setInputs] = useState<RoofInputs>({
    ancho: 30,
    proyeccion: 5,
    pendiente: 7,
    separacion: 1.5,
  });

  const [results, setResults] = useState<CalculationResult[]>([]);
  const [hasCalculated, setHasCalculated] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { id, value } = e.target;
    setInputs(prev => ({
      ...prev,
      [id]: parseFloat(value) || 0
    }));
  };

  const handleCalculate = (e: React.FormEvent) => {
    e.preventDefault();
    const data = calculateRoofData(inputs);
    setResults(data);
    setHasCalculated(true);
    // Smooth scroll to results on mobile
    if (window.innerWidth < 768) {
        window.scrollTo({ top: 600, behavior: 'smooth' });
    }
  };

  const resetForm = () => {
    setInputs({ ancho: 0, proyeccion: 0, pendiente: 0, separacion: 1.5 });
    setResults([]);
    setHasCalculated(false);
  };

  const copyToClipboard = () => {
    const text = results.map(r => `${r.label}: ${r.value}`).join('\n');
    navigator.clipboard.writeText(`Kingspan Project Summary:\n${text}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="min-h-screen pb-12">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center gap-4">
             <div className="bg-blue-900 px-4 py-2 rounded text-white font-black text-xl tracking-tighter">KINGSPAN</div>
             <div className="hidden sm:block h-8 w-px bg-slate-200"></div>
             <h1 className="hidden sm:block text-slate-500 font-medium text-sm">Roof Calculator Pro</h1>
          </div>
          <div className="flex items-center gap-3">
            <span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-2 py-1 rounded-full uppercase">Technical Tool v2.5</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 mt-8">
        <div className="grid lg:grid-cols-12 gap-8 items-start">

          {/* Form Section */}
          <div className="lg:col-span-5 space-y-6">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 md:p-8">
              <h2 className="text-2xl font-bold text-slate-800 mb-6">Configuración de Proyecto</h2>

              <div className="mb-8 overflow-hidden rounded-xl border border-slate-100 bg-slate-50">
                <img 
                    src="https://i.ibb.co/0R80GgpY/JPG-Una-Pendiente.jpg" 
                    alt="Diagrama Monopendiente" 
                    className="w-full object-cover h-48 opacity-90 hover:opacity-100 transition-opacity"
                />
              </div>

              <form onSubmit={handleCalculate} className="space-y-5">
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Ancho de la Cubierta (A) [m]</label>
                  <div className="relative">
                    <input 
                        id="ancho"
                        type="number" 
                        step="0.01"
                        required
                        value={inputs.ancho || ''}
                        onChange={handleInputChange}
                        className="w-full pl-4 pr-12 py-3 bg-white border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all font-medium text-lg"
                        placeholder="0.00"
                    />
                    <span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 font-medium">m</span>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Proyección (B) [m]</label>
                    <div className="relative">
                      <input 
                        id="proyeccion"
                        type="number" 
                        step="0.01"
                        required
                        value={inputs.proyeccion || ''}
                        onChange={handleInputChange}
                        className="w-full px-4 py-3 bg-white border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                      />
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Pendiente (%)</label>
                    <div className="relative">
                      <input 
                        id="pendiente"
                        type="number" 
                        step="0.1"
                        required
                        value={inputs.pendiente || ''}
                        onChange={handleInputChange}
                        className="w-full px-4 py-3 bg-white border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                      />
                    </div>
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Separación Correas (S) [m]</label>
                  <input 
                    id="separacion"
                    type="number" 
                    step="0.01"
                    required
                    value={inputs.separacion || ''}
                    onChange={handleInputChange}
                    className="w-full px-4 py-3 bg-white border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                  />
                </div>

                <div className="flex gap-3 pt-4">
                  <button 
                    type="submit" 
                    className="flex-1 bg-blue-700 hover:bg-blue-800 text-white font-bold py-4 rounded-xl shadow-lg shadow-blue-200 transition-all active:scale-[0.98]"
                  >
                    Calcular Materiales
                  </button>
                  <button 
                    type="button" 
                    onClick={resetForm}
                    className="px-5 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl transition-all"
                  >
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>
                  </button>
                </div>
              </form>
            </div>
          </div>

          {/* Results Section */}
          <div className="lg:col-span-7 space-y-6">
            {!hasCalculated ? (
              <div className="h-full min-h-[400px] flex flex-col items-center justify-center bg-slate-100/50 border-2 border-dashed border-slate-200 rounded-3xl p-12 text-center">
                <div className="bg-white p-4 rounded-full shadow-sm mb-4">
                  <svg className="w-12 h-12 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                  </svg>
                </div>
                <h3 className="text-xl font-bold text-slate-800">Listo para Analizar</h3>
                <p className="text-slate-500 max-w-sm mt-2">Ingrese las dimensiones del proyecto para obtener el desglose técnico y asesoría de materiales.</p>
              </div>
            ) : (
              <div className="animate-fade-in space-y-6">
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 md:p-8">
                  <div className="flex justify-between items-center mb-8">
                    <h2 className="text-2xl font-bold text-slate-800">Resultado del Análisis</h2>
                    <button 
                        onClick={copyToClipboard}
                        className={`px-4 py-2 rounded-lg text-sm font-bold transition-all duration-300 flex items-center gap-2 border ${copied ? 'bg-emerald-50 text-emerald-600 border-emerald-200' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
                    >
                      {copied ? (
                        <><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M5 13l4 4L19 7" strokeWidth={3} strokeLinecap="round" strokeLinejoin="round" /></svg> Copiado</>
                      ) : (
                        <><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round" /></svg> Copiar Datos</>
                      )}
                    </button>
                  </div>

                  <div className="grid sm:grid-cols-2 gap-4">
                    {results.map((res, i) => (
                      <ResultCard key={i} result={res} />
                    ))}
                  </div>

                  <div className="mt-8 p-4 bg-slate-50 rounded-xl border border-slate-200">
                    <div className="flex items-start gap-3">
                       <svg className="w-5 h-5 text-slate-400 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                       <p className="text-xs text-slate-500 leading-relaxed italic">
                        Esta estimación técnica es referencial y debe ser validada por un ingeniero estructural o el equipo técnico de Kingspan antes de la compra final. Los cálculos consideran traslapos técnicos estándar de 20cm.
                       </p>
                    </div>
                  </div>
                </div>

                <GeminiExpert inputs={inputs} results={results} />
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-20 border-t border-slate-200 pt-12 pb-8 px-4 text-center">
        <div className="max-w-6xl mx-auto">
          <p className="text-slate-400 text-sm font-medium">© 2024 Kingspan Group - Herramienta de Ingeniería Avanzada</p>
          <div className="flex justify-center gap-6 mt-4">
             <a href="#" className="text-slate-300 hover:text-blue-600 transition-colors text-xs uppercase tracking-widest font-bold">Manual Técnico</a>
             <a href="#" className="text-slate-300 hover:text-blue-600 transition-colors text-xs uppercase tracking-widest font-bold">Catálogo Paneles</a>
             <a href="#" className="text-slate-300 hover:text-blue-600 transition-colors text-xs uppercase tracking-widest font-bold">Soporte</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

